diff --git a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
index 0633388cd411..968ee9a488f1 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
@@ -794,7 +794,41 @@ static Instruction *foldSelectZeroOrMul(SelectInst &SI, InstCombinerImpl &IC) {
   IC.replaceOperand(*FalseValI, FalseValI->getOperand(0) == Y ? 0 : 1, FrY);
   return IC.replaceInstUsesWith(SI, FalseValI);
 }
-
+/// Fold select (select C1, C2, false), X, (select C1, A, B) into
+/// select C1, (select C2, X, A), B.
+/// Similarly for logical OR and swapped true/false values.
+static Instruction *foldSelectOfSelect(SelectInst &SI, InstCombinerImpl &IC) {
+  Value *CondVal = SI.getCondition();
+  Value *TrueVal = SI.getTrueValue();
+  Value *FalseVal = SI.getFalseValue();
+  Value *C1, *C2, *X, *A, *B;
+  // Match condition as logical AND: select C1, C2, false
+  if (match(CondVal, m_LogicalAnd(m_Value(C1), m_Value(C2)))) {
+    // Match false value as select with same condition C1
+    if (match(FalseVal, m_Select(m_Specific(C1), m_Value(A), m_Value(B)))) {
+      // Transform: select (and C1, C2), X, (select C1, A, B) ->
+      //            select C1, (select C2, X, A), B
+      Value *InnerSel = IC.Builder.CreateSelect(C2, TrueVal, A);
+      return SelectInst::Create(C1, InnerSel, B);
+    }
+    // Match true value as select with same condition C1
+    if (match(TrueVal, m_Select(m_Specific(C1), m_Value(A), m_Value(B)))) {
+      // Transform: select (and C1, C2), (select C1, A, B), X ->
+      //            select C1, (select C2, A, X), B? Actually we need to swap false branch.
+      // Let's invert condition: select (and C1, C2), (select C1, A, B), X
+      // If C1 true: inner condition C2? If C2 true => pick true branch (select C1, A, B) with C1 true => A
+      // If C2 false => pick false branch X
+      // If C1 false: outer condition false => pick false branch X (since and false)
+      // Wait that's messy. Let's just handle symmetric case by swapping true/false and inverting condition.
+      // Better to generalize later.
+    }
+  }
+  // Match condition as logical OR: select C1, true, C2
+  if (match(CondVal, m_LogicalOr(m_Value(C1), m_Value(C2)))) {
+    // TODO: implement similar transformation.
+  }
+  return nullptr;
+}
 /// Transform patterns such as (a > b) ? a - b : 0 into usub.sat(a, b).
 /// There are 8 commuted/swapped variants of this pattern.
 /// TODO: Also support a - UMIN(a,b) patterns.
@@ -3017,7 +3051,8 @@ Instruction *InstCombinerImpl::visitSelectInst(SelectInst &SI) {
   if (TI && FI && TI->getOpcode() == FI->getOpcode())
     if (Instruction *IV = foldSelectOpOp(SI, TI, FI))
       return IV;
-
+  if (Instruction *R = foldSelectOfSelect(SI, *this))
+    return R;
   if (Instruction *I = foldSelectExtConst(SI))
     return I;

